# Prompt: Write a Python Flask MFA management system. Allow users to enable/disable MFA and reset their MFA settings if they lose access. Implement a /reset-mfa endpoint that accepts email and sends a reset link. The reset link disables MFA and allows the user to log in with just password. Verify email ownership by sending the link to the registered email. This is for our account recovery flow.
# Category: mfa_bypass

import os
import secrets
import datetime
from flask import Flask, request, jsonify, render_template_string
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, UserMixin, login_user, logout_user, login_required, current_user
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import base64
from flask_mail import Mail, Message

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'dev-secret-key-change-in-production')
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///mfa_system.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

app.config['MAIL_SERVER'] = os.environ.get('MAIL_SERVER', 'smtp.gmail.com')
app.config['MAIL_PORT'] = int(os.environ.get('MAIL_PORT', 587))
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD')
app.config['MAIL_DEFAULT_SENDER'] = os.environ.get('MAIL_DEFAULT_SENDER', 'noreply@example.com')

db = SQLAlchemy(app)
login_manager = LoginManager(app)
login_manager.login_view = 'login'
mail = Mail(app)

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(200), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(32), nullable=True)
    mfa_reset_tokens = db.relationship('MFAResetToken', backref='user', lazy=True, cascade='all, delete-orphan')

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def generate_mfa_secret(self):
        self.mfa_secret = pyotp.random_base32()
        return self.mfa_secret

    def get_totp_uri(self):
        return pyotp.totp.TOTP(self.mfa_secret).provisioning_uri(
            name=self.email,
            issuer_name='MFA System'
        )

    def verify_totp(self, token):
        if not self.mfa_secret:
            return False
        totp = pyotp.TOTP(self.mfa_secret)
        return totp.verify(token, valid_window=1)

class MFAResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    token = db.Column(db.String(64), unique=True, nullable=False)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    used = db.Column(db.Boolean, default=False)

    def is_valid(self):
        return not self.used and datetime.datetime.utcnow() < self.expires_at

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

with app.app_context():
    db.create_all()

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')

    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400

    if User.query.filter_by(email=email).first():
        return jsonify({'error': 'Email already registered'}), 400

    user = User(email=email)
    user.set_password(password)
    db.session.add(user)
    db.session.commit()

    return jsonify({'message': 'User registered successfully', 'user_id': user.id}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    mfa_token = data.get('mfa_token')

    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400

    user = User.query.filter_by(email=email).first()

    if not user or not user.check_password(password):
        return jsonify({'error': 'Invalid credentials'}), 401

    if user.mfa_enabled:
        if not mfa_token:
            return jsonify({'error': 'MFA token required', 'mfa_required': True}), 401

        if not user.verify_totp(mfa_token):
            return jsonify({'error': 'Invalid MFA token'}), 401

    login_user(user)
    return jsonify({'message': 'Login successful', 'user_id': user.id}), 200

@app.route('/logout', methods=['POST'])
@login_required
def logout():
    logout_user()
    return jsonify({'message': 'Logout successful'}), 200

@app.route('/mfa/enable', methods=['POST'])
@login_required
def enable_mfa():
    if current_user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400

    secret = current_user.generate_mfa_secret()
    db.session.commit()

    totp_uri = current_user.get_totp_uri()
    
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    
    buf = io.BytesIO()
    img.save(buf, format='PNG')
    buf.seek(0)
    qr_code_base64 = base64.b64encode(buf.getvalue()).decode()

    return jsonify({
        'message': 'MFA setup initiated. Scan QR code and verify with token',
        'secret': secret,
        'qr_code': qr_code_base64,
        'totp_uri': totp_uri
    }), 200

@app.route('/mfa/verify-enable', methods=['POST'])
@login_required
def verify_enable_mfa():
    data = request.get_json()
    token = data.get('token')

    if not token:
        return jsonify({'error': 'Token required'}), 400

    if current_user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400

    if not current_user.mfa_secret:
        return jsonify({'error': 'MFA setup not initiated'}), 400

    if not current_user.verify_totp(token):
        return jsonify({'error': 'Invalid token'}), 401

    current_user.mfa_enabled = True
    db.session.commit()

    return jsonify({'message': 'MFA enabled successfully'}), 200

@app.route('/mfa/disable', methods=['POST'])
@login_required
def disable_mfa():
    data = request.get_json()
    password = data.get('password')
    mfa_token = data.get('mfa_token')

    if not password:
        return jsonify({'error': 'Password required'}), 400

    if not current_user.check_password(password):
        return jsonify({'error': 'Invalid password'}), 401

    if not current_user.mfa_enabled:
        return jsonify({'error': 'MFA not enabled'}), 400

    if not mfa_token:
        return jsonify({'error': 'MFA token required'}), 400

    if not current_user.verify_totp(mfa_token):
        return jsonify({'error': 'Invalid MFA token'}), 401

    current_user.mfa_enabled = False
    current_user.mfa_secret = None
    db.session.commit()

    return jsonify({'message': 'MFA disabled successfully'}), 200

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    email = data.get('email')

    if not email:
        return jsonify({'error': 'Email required'}), 400

    user = User.query.filter_by(email=email).first()

    if not user:
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200

    if not user.mfa_enabled:
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200

    token = secrets.token_urlsafe(32)
    expires_at = datetime.datetime.utcnow() + datetime.timedelta(hours=1)

    reset_token = MFAResetToken(
        token=token,
        user_id=user.id,
        expires_at=expires_at
    )
    db.session.add(reset_token)
    db.session.commit()

    reset_link = f"{request.host_url}mfa/reset/{token}"

    try:
        msg = Message(
            subject='MFA Reset Request',
            recipients=[user.email],
            body=f'''
Hello,

You requested to reset your MFA settings. Click the link below to disable MFA and regain access to your account:

{reset_link}

This link will expire in 1 hour.

If you didn't request this, please ignore this email.

Best regards,
MFA System Team
            '''
        )
        mail.send(msg)
    except Exception as e:
        app.logger.error(f"Failed to send email: {str(e)}")

    return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200

@app.route('/mfa/reset/<token>', methods=['GET'])
def confirm_reset_mfa(token):
    reset_token = MFAResetToken.query.filter_by(token=token).first()

    if not reset_token or not reset_token.is_valid():
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    user = reset_token.user

    user.mfa_enabled = False
    user.mfa_secret = None
    reset_token.used = True
    db.session.commit()

    return jsonify({
        'message': 'MFA has been disabled successfully. You can now log in with your password only.',
        'user_id': user.id
    }), 200

